import{_ as t,o as s,c as a,ae as e}from"./chunks/framework.Czhw_PXq.js";const i="/assets/image1.Bd-NIPch.png",n="/assets/image2.DlAHhjCQ.png",o="/assets/image3.BoP8ZX8G.png",r="/assets/image4.CM7_oBpK.png",c="/assets/image5.BcuVhGgV.png",m="/assets/image6.DxUwhkQX.png",_="/assets/image7.RY5j-K8s.png",g="/assets/image8.RYW4KD2d.png",u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"0420lab.md","filePath":"0420lab.md"}'),l={name:"0420lab.md"};function d(b,p,B,f,G,S){return s(),a("div",null,[...p[0]||(p[0]=[e('<p>0420 实验报告</p><p>实验1</p><p>使用GDB发现两处a的地址差了80byte，且总如此</p><p><img src="'+i+'" alt=""></p><p>使用x分析内存分布情况</p><p><img src="'+n+'" alt=""></p><p>可以看到dc90（栈底）这里填写了1（i的值，不总写在这，2的时候我观察到写在dc40的最右侧），从这里一直到dcb7全部都是int数组的空间，dcb0我了解到是编译器自己加的一个哨兵，dcc0分别是saved rbp以及对应的返回地址，最后这行全为0非常奇怪，推测可能是padding（但也不应该啊，按道理64是最好的），以及其实我注意到如果i=2的时候这里就不全为0了，然而我无法理解这里存的是什么，可能是中间的一些地址？</p><p>实验2</p><p>一开始使用1024代入直接失败，Program terminated with signal SIGSEGV, Segmentation fault，且在main函数就直接GG，这是因为long数组占据了8MB的内存，而栈空间最多8MB，肯定还要算上那些rbprsp指针的空间，显然超过了8MB</p><p><img src="'+o+'" alt=""></p><p>因此直接改为512，用GDB看看怎么个事</p><p>观察到差了8byte，这是因为数组地址是紧挨着排的，a地址也就是首元素地址如果是dd20结尾，那a[0][1]自然是dd28结尾，差一个long（8byte）</p><p>我了解到，大部分程序会聪明的利用堆空间，栈主要是用于存小型变量，主打控制，所以大部分程序不会崩</p><p>查资料 我了解到最直接的办法是设置系统，修改栈空间上限</p><p><img src="'+r+'" alt=""></p><p>但最根本的方法还是要利用堆，自己手写malloc分配空间</p><p>实验3</p><p>将long 数组放在了main外面，可以跑了</p><p>地址出现在.data段，即可读写数据段</p><p>以及差值依旧为8保持不变</p><p><img src="'+c+'" alt=""></p><p>实验4</p><p>我定义了c = long[10][20][30]</p><p>对于a来说从0到1要跨越所有后面的空间，20*30=600，非常合理</p><p><img src="'+m+'" alt=""></p><p>实验5</p><p><img src="'+_+'" alt=""></p><p>这个实验很有意思，当我使用1000的时候，是可以正常运行的，返回的是一个垃圾值17748，这是因为1000越过了数组100的边界，但是还在页内</p><p>我于是把1000改成1000000，结果就出现了一个0x8开头的，我就知道不对了，因为栈底应该也就0x7f开头，肯定溢出了，这边也显示无法获取该地址的内存，最后运行也显示无法运行，程序被终止</p><p><img src="'+g+'" alt=""></p>',30)])])}const x=t(l,[["render",d]]);export{u as __pageData,x as default};
